 26→const getPercentageStyle = (percentage: number): React.CSSProperties => {
 27→	const adjustedPercentage = Math.max(0, percentage - 5);
 28→	const intensity = Math.min(adjustedPercentage / 25, 1);
 29→	const red = Math.round(245 + (248 - 245) * intensity);
 30→	const green = Math.round(245 * (1 - intensity));
 31→	const blue = Math.round(245 * (1 - intensity));
 32→	const bgColor = `rgb(${red}, ${green}, ${blue})`;
 33→	const textColor = intensity > 0.4 ? '#ffffff' : '#666';
 34→	return { background: bgColor, color: textColor };
 35→};
